/**
 * CSS filter to convert the white logo to red (#E60000)
 * Use this on img tags where logo should appear red (header, splash, receipts)
 * Do NOT use on balance cards where white logo is needed
 */
export const RED_LOGO_FILTER = "brightness(0) saturate(100%) invert(14%) sepia(93%) saturate(7431%) hue-rotate(358deg) brightness(97%) contrast(115%)";

/**
 * Transparent PNG logo - use inside the app (splash screen, cards, header)
 */
export const LOGO_BASE64 = "data:image/png;base64,";

/**
 * Blue background JPEG icon - use as app icon reference
 */
export const APP_ICON_BASE64 = "data:image/jpeg;base64,";
